import React, { useState } from "react";
import defaultImg from "../../image/default.jpg";
// import background1 from ".";
import background1 from '../../image/background1.jpg'


function Application(props) {


    const saveProfile = JSON.parse(localStorage.getItem("userProfile")) || {};
    const saveImg = localStorage.getItem("profileImg");

    const [user, setUser] = useState({})

    // state = {
    //   firstName: saveProfile.firstName || "",
    //   lastName: saveProfile.lastName || "",
    //   age: saveProfile.age || "",
    //   email: saveProfile.email || "",
    //   mobile: saveProfile.mobile || "",
    //   height: saveProfile.height || "",
    //   institute: saveProfile.institute || "",
    //   bloodGroup: saveProfile.bloodGroup || "",
    //   district: saveProfile.district || "",
    //   birthday: saveProfile.birthday || "",
    //   gender: saveProfile.gender || "",
    //   profileImg: saveImg || defaultImg,
    // };

    const fileInputRef = React.createRef();

  const handleChange = (event) => {
    const { name, value } = event.target;
    setUser({ [name]: value });
  };

  const handleProfileChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        localStorage.setItem("profileImg", e.target.result);
        setUser({ profileImg: e.target.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    localStorage.setItem("userProfile", JSON.stringify(user));
    alert("✅ Profile updated successfully!");
  };

  return (
    <div
      className="profile-background"
      style={{ backgroundImage: `url(${background1})` }}

    >
      <div className="profile-card transparent-card">
        <h3 className="text-center mb-4">Edit Profile</h3>

        {/* Profile Image */}
        <div className="text-center mb-3">
          <img
            src={user.profileImg}
            alt="Profile"
            className="profile-pic"
          />
          <br />
          <button
            className="btn btn-sm btn-outline-light mt-2"
            onClick={() => fileInputRef.current.click()}
          >
            Change Image
          </button>
          <input
            type="file"
            accept="image/*"
            style={{ display: "none" }}
            ref={fileInputRef}
            onChange={handleProfileChange}
          />
        </div>

        {/* Profile Form */}
        <form onSubmit={handleSubmit}>
          <div className="row mb-3">
            <div className="col">
              <label>First Name</label>
              <input
                type="text"
                className="form-control"
                name="firstName"
                value={user.firstName}
                onChange={handleChange}
              />
            </div>
            <div className="col">
              <label>Last Name</label>
              <input
                type="text"
                className="form-control"
                name="lastName"
                value={user.lastName}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="row mb-3">
            <div className="col">
              <label>Age</label>
              <input
                type="number"
                className="form-control"
                name="age"
                value={user.age}
                onChange={handleChange}
              />
            </div>
            <div className="col">
              <label>Gender</label>
              <input
                type="text"
                className="form-control"
                name="gender"
                value={user.gender}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="mb-3">
            <label>Email</label>
            <input
              type="email"
              className="form-control"
              name="email"
              value={user.email}
              onChange={handleChange}
            />
          </div>

          <div className="mb-3">
            <label>Mobile</label>
            <input
              type="text"
              className="form-control"
              name="mobile"
              value={user.mobile}
              onChange={handleChange}
            />
          </div>

          <div className="row mb-3">
            <div className="col">
              <label>Height</label>
              <input
                type="text"
                className="form-control"
                name="height"
                value={user.height}
                onChange={handleChange}
              />
            </div>
            <div className="col">
              <label>Blood Group</label>
              <input
                type="text"
                className="form-control"
                name="bloodGroup"
                value={user.bloodGroup}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="mb-3">
            <label>Institute</label>
            <input
              type="text"
              className="form-control"
              name="institute"
              value={user.institute}
              onChange={handleChange}
            />
          </div>

          <div className="row mb-3">
            <div className="col">
              <label>District</label>
              <input
                type="text"
                className="form-control"
                name="district"
                value={user.district}
                onChange={handleChange}
              />
            </div>
            <div className="col">
              <label>Birthday</label>
              <input
                type="text"
                className="form-control"
                name="birthday"
                placeholder="DD-MM-YYYY"
                value={user.birthday}
                onChange={handleChange}
              />
            </div>
          </div>

          <button type="submit" className="btn btn-success w-100">
            Save Changes
          </button>
        </form>
      </div>
    </div>
  );
}

export default Application;
